// 1. Safely receive text (whether named output or text)
const aiResponse = $json.output || $json.text;

// 2. Safety check: If no data, stop and output a clear error message
if (!aiResponse) {
  throw new Error("Alert: No response received from AI (variable is empty).");
}

// 3. Clean text from Markdown tags (```json)
const cleanJson = aiResponse.replace(/```json/g, '').replace(/```/g, '').trim();

// 4. Convert text to JSON object and return
return JSON.parse(cleanJson);

// 1. Receive output from the Agent
const rawOutput = $input.all()[0].json.output;

try {
  // 2. Search for JSON (employee data) inside the text
  const jsonMatch = rawOutput.match(/\{[\s\S]*\}/);

  if (jsonMatch) {
    // If data is found, parse it and pass it through
    const cleanJson = JSON.parse(jsonMatch[0]);
    return [{ json: { ...cleanJson, is_valid: true } }];
  } else {
    // If it's a regular message, send false to close the route smoothly
    return [{ json: { is_valid: false } }];
  }
} catch (e) {
  // In case of any error, close the route without stopping the workflow
  return [{ json: { is_valid: false } }];
}

