// 1. Get attendance time from the previous node
const attendanceStr = $('Get_Arrival_Time').item.json['التاريخ والوقت'];
const attendanceTime = new Date(attendanceStr);

// 2. Get current departure time
const departureTime = new Date($('Parse_AI_Response').item.json.timestamp);

// 3. Calculate time difference
const diffInMs = departureTime - attendanceTime;
const diffInHours = diffInMs / (1000 * 60 * 60);

// 4. Apply 8-hour rule
let penaltyNotes = "Normal departure";
let isPenalty = false;

if (diffInHours < 8) {
    penaltyNotes = `Early departure (worked only ${diffInHours.toFixed(2)} hours)`;
    isPenalty = true;
}

return {
    attendance_time: attendanceStr,
    departure_time: departureTime.toLocaleString(),
    hours_worked: diffInHours.toFixed(2),
    is_early_departure: isPenalty,
    notes: penaltyNotes
};

