const allEmployees = $items("Fetch_All_Employees"); // Must exactly match node name "Fetch_All_Employees"
const todayAttendance = $items("Filter_Today_Attendance"); // Must exactly match node name "Filter_Today_Attendance"

const attendedIds = todayAttendance.map(item => item.json["كود الموظف"]);
const absentees = allEmployees.filter(emp => !attendedIds.includes(emp.json["كود الموظف"]));

return absentees;

